CREATE TABLE t0 (c0 INTEGER, c1 INTEGER);
SELECT subq1.c8 AS c9 FROM (SELECT TRUE AS c8 FROM (SELECT t1.c1 AS c5 FROM t0 AS t1 WHERE t1.c1 = t1.c0 ORDER BY c5 LIMIT 5819351589579946652) AS subq0 WHERE NOT TRIM(67, NULL) IS NULL ORDER BY c8) AS subq1 WHERE subq1.c8 <> CASE subq1.c8 WHEN subq1.c8 = CASE WHEN subq1.c8 = subq1.c8 OR TRUE THEN CAST(subq1.c8 AS INTEGER) ELSE subq1.c8 END THEN subq1.c8 ELSE subq1.c8 END ORDER BY c9